+function createNonTtyStream() {
+  let text = ''
+  const stream = new Writable({
+    write(chunk, _encoding, callback) {
+      text += chunk.toString()
+      callback()
+    },
+  })
+  ;(stream as unknown as { isTTY?: boolean }).isTTY = false
+  return { stream, getText: () => text }
+}
